const today = new Date().toISOString().slice(0, 10);

const categories = [
  {
    category: 'it-trend',
    categoryLabel: 'it-trend',
    enabled: true,
    sourceCandidates: [
      {
        label: 'GitHub Blog',
        kind: 'rss',
        url: 'https://github.blog/feed/',
        enabled: true,
        primary: true,
        notes: 'verified'
      },
      {
        label: 'Hacker News',
        kind: 'rss',
        url: 'https://news.ycombinator.com/rss',
        enabled: true,
        notes: 'verified'
      },
      {
        label: 'Cloudflare Blog',
        kind: 'rss',
        url: 'https://blog.cloudflare.com/rss/',
        enabled: true,
        notes: 'verified'
      },
      {
        label: 'TechCrunch',
        kind: 'rss',
        url: 'https://techcrunch.com/feed/',
        enabled: true,
        notes: 'verified'
      },
      {
        label: 'The Verge',
        kind: 'rss',
        url: 'https://www.theverge.com/rss/index.xml',
        enabled: true,
        notes: 'verified'
      },
      {
        label: 'OpenAI Blog',
        kind: 'rss',
        url: 'https://openai.com/blog/rss.xml',
        enabled: true,
        notes: 'verified'
      },
      {
        label: 'Google Cloud Blog',
        kind: 'rss',
        url: 'https://cloud.google.com/blog/rss.xml',
        enabled: false,
        notes: 'verify before enabling'
      },
      {
        label: 'Firebase Blog',
        kind: 'rss',
        url: 'https://firebase.blog/feed.xml',
        enabled: false,
        notes: 'replace with current URL before enabling'
      }
    ]
  },
  {
    category: 'japan',
    categoryLabel: 'japan',
    enabled: false,
    sourceCandidates: [
      {
        label: 'Digital Agency',
        kind: 'rss',
        url: 'https://www.digital.go.jp/rss/news.xml',
        enabled: true,
        primary: true,
        notes: 'verified'
      },
      {
        label: 'NHK News',
        kind: 'rss',
        url: 'https://www.nhk.or.jp/rss/news/cat0.xml',
        enabled: true,
        notes: 'verified'
      },
      {
        label: 'ITmedia NEWS',
        kind: 'rss',
        url: 'https://rss.itmedia.co.jp/rss/2.0/news_bursts.xml',
        enabled: true,
        notes: 'verified'
      },
      {
        label: 'Impress Watch',
        kind: 'manual',
        url: '',
        enabled: false,
        notes: 'find and verify the current feed URL before enabling'
      }
    ]
  },
  {
    category: 'world',
    categoryLabel: 'world',
    enabled: false,
    sourceCandidates: [
      {
        label: 'BBC News',
        kind: 'rss',
        url: 'https://feeds.bbci.co.uk/news/rss.xml',
        enabled: true,
        primary: true,
        notes: 'verified'
      },
      {
        label: 'The Guardian',
        kind: 'rss',
        url: 'https://www.theguardian.com/world/rss',
        enabled: true,
        notes: 'verified'
      },
      {
        label: 'NPR',
        kind: 'rss',
        url: 'https://feeds.npr.org/1001/rss.xml',
        enabled: true,
        notes: 'verified'
      },
      {
        label: 'Reuters',
        kind: 'manual',
        url: '',
        enabled: false,
        notes: 'verify a public RSS endpoint before enabling'
      },
      {
        label: 'AP News',
        kind: 'manual',
        url: '',
        enabled: false,
        notes: 'verify a public RSS endpoint before enabling'
      },
      {
        label: 'World Economic Forum',
        kind: 'manual',
        url: '',
        enabled: false,
        notes: 'verify a public RSS endpoint before enabling'
      }
    ]
  }
];

return categories.map((category) => {
  const activeCandidate = category.sourceCandidates.find((candidate) => candidate.enabled && candidate.url) ??
    category.sourceCandidates.find((candidate) => candidate.enabled) ??
    null;

  return {
    json: {
      ...category,
      rssUrl: activeCandidate?.url ?? '',
      selectedSourceCandidate: activeCandidate,
      slugPrefix: `${today}-${category.category}-`,
      sourceHint: category.sourceCandidates
        .filter((candidate) => candidate.enabled)
        .map((candidate) => candidate.label)
        .join(', ')
    }
  };
});

const rawFeed = typeof $json.body === 'string' ? $json.body : (typeof $json.data === 'string' ? $json.data : JSON.stringify($json));

const itemMatches = [...rawFeed.matchAll(/<item>[\s\S]*?<title>(.*?)<\/title>[\s\S]*?<link>(.*?)<\/link>[\s\S]*?<\/item>/gi)];
const parsedSources = itemMatches.slice(0, 3).map((match, index) => ({
  label: match[1].trim() || `${$json.categoryLabel} source ${index + 1}`,
  url: match[2].trim()
})).filter((source) => /^https?:\/\//i.test(source.url));

const titleMatches = [...rawFeed.matchAll(/<title>(.*?)<\/title>/gi)].map((match) => match[1].trim()).filter(Boolean);
const headlineHints = titleMatches.slice(1, 5);

return [
  {
    json: {
      ...$json,
      parsedSources: parsedSources.length > 0 ? parsedSources : [
        {
          label: `${$json.categoryLabel} RSS placeholder`,
          url: $json.rssUrl
        }
      ],
      headlineHints,
      feedExcerpt: rawFeed.slice(0, 4000)
    }
  }
];

let article;
try {
  const content = $json.choices?.[0]?.message?.content ?? '{}';
  article = JSON.parse(content);
} catch (error) {
  article = {
    slug: `${$json.slugPrefix}fallback-${Date.now()}`,
    title: `${$json.categoryLabel} update`,
    category: $json.category,
    publishedAt: $json.publishedAt,
    summaryLines: [
      `${$json.categoryLabel} autopost fallback article.`,
      'This example is for workflow testing.',
      'Replace the RSS feeds and prompt before production use.'
    ],
    bodyLines: [
      'OpenAI output was not readable as JSON, so a fallback article was created.',
      'Check the prompt and response shape before real use.'
    ],
    whyItMatters: 'This keeps the autopost pipeline testable.',
    tomoPoint: 'Start small, then refine the RSS and prompt.',
    thumbnailUrl: 'https://images.unsplash.com/photo-1516321318423-f06f85e504b3?auto=format&fit=crop&w=1200&q=80',
    tags: ['autopost', $json.category],
    sources: $json.parsedSources,
    initialEditorComment: {
      bodyLines: ['Autopost sample article. Please verify RSS and OpenAI connectivity.'],
      authorName: 'editor',
      shortId: 'editor'
    }
  };
}

const normalizedArticle = {
  ...article,
  category: article.category || $json.category,
  publishedAt: article.publishedAt || $json.publishedAt,
  sources: Array.isArray(article.sources) && article.sources.length > 0 ? article.sources : $json.parsedSources,
  initialEditorComment: article.initialEditorComment ?? {
    bodyLines: ['Autopost sample article.'],
    authorName: 'editor',
    shortId: 'editor'
  }
};

return [
  {
    json: {
      ...$json,
      articlePayload: normalizedArticle
    }
  }
];

const statusCode = $json.statusCode ?? 409;

return [
  {
    json: {
      statusCode,
      created: false,
      skipped: true,
      processed: false,
      createdCommentCount: null,
      aiReplySweeps: 0,
      note: 'duplicate-slug-skipped'
    }
  }
];

const createdCommentCount = typeof $json.createdCommentCount === 'number' ? $json.createdCommentCount : null;
const processed = $json.processed === true;

return [
  {
    json: {
      statusCode: $json.statusCode ?? 200,
      created: true,
      skipped: false,
      processed,
      createdCommentCount,
      aiReplySweeps: 3,
      note: processed ? 'created-and-swept' : 'created-no-queued-job'
    }
  }
];
